var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"10년 후, 겨울","JPN":"10年後、冬","ENG":"Ten years later, winter.","TWN":"10年後的冬天"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"후우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼…"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"보고 드립니다.","JPN":"報告します。","ENG":"Reporting in.","TWN":"報告。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"작전 중 악화된 용혈이 결국 폭주했고… 주시 대상은 사망했어요.","JPN":"作戦中悪化した龍血が暴走し……監視対象は死亡しました。","ENG":"During the operation, the Dragon Blood condition worsened and eventually went out of control… The subject is dead.","TWN":"作戰中惡化的龍血最終暴走了…監視對象死亡了。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"많이 힘들어 보이는군요.","JPN":"疲れているようですね。","ENG":"You look like you've been through a lot.","TWN":"你看起來很辛苦。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 감시만 하라고 했을 텐데, 그 사람의 폭주를 직접 막으려 했던 건가요?","JPN":"僕が指示したのは監視だけのはずですが、彼女の暴走を止めようとしたのですか？","ENG":"I told you to observe. Did you try to stop her rampage yourself?","TWN":"我只讓你監視，但你是不是親自去阻止她的暴走了？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…면목 없습니다, 대장.","JPN":"……申し訳ありません、隊長。","ENG":"…I accept full responsibility, Commander.","TWN":"…很抱歉，隊長。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"생애 가장 행복해야 할 순간에 죽는다… 정말 안타까운 비극이지만, 운명에 우리가 관여할 수 있는 건 없어요.","JPN":"最も幸せであるべき瞬間に死ぬ……残念でならない悲劇ですが、僕たちが運命に干渉できる術はありません。","ENG":"To die in the happiest moment of one's life… A tragic end, no doubt. But fate isn't something we can change.","TWN":"在人生最幸福的時刻死去…雖然是個令人惋惜的悲劇，但我們無法干涉命運。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래도 당신이 무사해서 다행이네요.","JPN":"ですが、あなたが無事でよかったです。","ENG":"Still, I'm relieved you made it back alive.","TWN":"不過，你平安無事真是太好了。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…마지막 순간, 예정대로 발키리가 개입해 폭주를 중재했습니다.","JPN":"……最後の瞬間、予定通りヴァルキリーが介入し、暴走を仲裁しました。","ENG":"…At the very end, Valkyrie intervened.","TWN":"…在最後一刻，女武神如預定地介入，阻止了暴走。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"제 정체를 들키진 않았습니다만… 그 여자도 전말을 모두 이해하고 있던 것처럼 태연하게 대응하더군요.","JPN":"正体はバレませんでしたが……前後の事情をすべて分かっていたかのように、冷静に対応していました。","ENG":"She didn't uncover my identity… but she acted like she already understood everything.","TWN":"我沒有暴露身分…但那個女人卻像是完全了解所有事情一樣，冷靜地應對。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"발키리는 저희와 달리, 정보를 접해서 알고 있는 게 아닙니다.","JPN":"ヴァルキリーは僕たちと違って、事前に情報を入手したから知っていたわけではありません。","ENG":"Valkyrie isn't like us. She didn't learn that through intel.","TWN":"女武神和我們不同，她不是從情報中得知的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇다면…?","JPN":"ということは……？","ENG":"Then…?","TWN":"那麼…？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"경험에서 우러나오는 반응이죠. 대격세혈맥의 보유자들을 수 없이 만나 왔을 테니까요.","JPN":"経験から出る反応です。対隔世血脈の保有者たちに幾度も会ってきたはずですから。","ENG":"It's from experience. She's crossed paths with Atavism hosts countless times.","TWN":"那是源於經驗的反應。她一定遇過無數大劫世血脈的擁有者。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 최후 또한 수 없이 보아왔을 겁니다.","JPN":"そして彼らの最期もまた、幾度も見てきたはずです。","ENG":"And she's watched each of them meet their end.","TWN":"她也見證了無數次的最終結局。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"여자의 아들은 그 아수라장에서도 결국 살아남았습니다.","JPN":"女の息子はあの修羅場でも生き残りました。","ENG":"Even in that chaos, the woman's son managed to survive.","TWN":"那名女子的兒子，即便身處那場混亂，最終仍然活了下來。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"생애 가장 행복한 순간이 아직 오지 않았다… 소년이 살아남은 이유는 그런 겁니다.","JPN":"まだ生涯で最も幸せな瞬間は訪れていない……少年が生き残った理由でしょう。","ENG":"Then maybe the happiest moment hadn't come yet… That could be why the boy lived.","TWN":"他人生最幸福的時刻還沒到來…這就是那個少年活下來的原因吧。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이로서 용혈보유자는 한 사람 밖에 남지 않게 됐군요.","JPN":"これで龍血の保有者は1人になりましたね。","ENG":"And now, there's only one Dragon Blood host left.","TWN":"如此一來，龍血擁有者只剩下一個人了。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고… 끝내 용혈의 저주를 이겨내지 못하는 최후를 맞게 되겠죠.","JPN":"そして……龍血の呪いに打ち勝てず最期を迎えるでしょう。","ENG":"And… like all the others, will eventually lose to the curse.","TWN":"而…他最終也會迎來無法戰勝龍血詛咒的結局。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금껏 그랬던 것처럼.","JPN":"今までそうだったように。","ENG":"Just like always.","TWN":"就像過去一樣。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"명달은 살아 생전 그 굴레의 끝을 본 적이 없어요. 그럼에도 용의 혈맥이 계속 이어지길 바라는 사람이었습니다.","JPN":"アカタツは生前、その循環の最後を見たことがありませんでした。にもかかわらず、彼は龍の血脈が続いてほしいと願っていました。","ENG":"Myeongdal never lived to see the end of that cycle. Yet he still wished the Dragon's bloodline would go on.","TWN":"明達生前從未見過這個循環的盡頭。儘管如此，他還是希望龍的血脈能夠繼續延續。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"미래를 보는 사람이었음에도 자신이 보지 못하는 걸 믿었을 지도 모르죠.","JPN":"未来を見ることのできる人間でありながらも、自分が見ることのできない何かを信じていたのかもしれません。","ENG":"Maybe, despite being someone who saw the future, he chose to believe in what he couldn't see.","TWN":"他雖然是個能預知未來的人，但或許他相信自己看不到的東西。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"훗날 그 악순환을 끊어낼 누군가 나타날 거라고.","JPN":"後日、その悪循環を断ち切る誰かが現れてくれると。","ENG":"That someday, someone would break the vicious cycle.","TWN":"總有一天，會有人出現，切斷這個惡性循環。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 가끔은 희망을 가져보자고요. 혹시 모르잖습니까.","JPN":"だからたまには希望を持ってみましょう。まだ分からないじゃないですか。","ENG":"So let's try having a little hope. You never know.","TWN":"所以，偶爾抱持希望吧。誰知道呢。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"연옥에 떨어진 번뇌룡이 이번 생에는 바라밀을 완성할 수 있을지.","JPN":"煉獄に落ちた龍が、今生では波羅蜜を完成できるか。","ENG":"Whether or not the dragon of Kleshas that has fallen into the purgatory can complete the Paramita in his current life.","TWN":"墜入煉獄的煩惱龍，這次能不能完成波羅蜜。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"찾았다.","JPN":"あった。","ENG":"Found it.","TWN":"找到了。"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"드디어… 아흔아홉 개.","JPN":"やっと……99個。","ENG":"Finally… that makes ninety-nine.","TWN":"終於…九十九個。"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"subtitle","speaker":null,"text":{"KOREA":"그 겨울, 챔버","JPN":"その冬、チェンバー","ENG":"That winter, Chamber.","TWN":"冬天，強巴"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이제 하나만 남았군요. 그동안 수고 많았습니다, 안드레아 베스카.","JPN":"これであと1つですね。今までご苦労様でした。アンドレア・ベスカー。","ENG":"Just one left now. You've done well, Andrea Vesca.","TWN":"現在只剩一個了。這段時間辛苦了，安德莉亞·貝斯卡。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"됐어, 됐어. 수고는 무슨.","JPN":"いいよいいよ。ねぎらいなんて。","ENG":"Yeah, yeah. No need to make it a big deal.","TWN":"沒事，沒事。什麼辛苦不辛苦的。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아저씨가 말했잖아. 편린을 전부 모았을 때부터가 시작이라고.","JPN":"おじさんが言ったでしょう。片鱗を全部集めてからがスタートだって。","ENG":"Didn't you say this would only truly start once I gathered all the fragments?","TWN":"大叔不是說了嗎？從收集完所有碎片的時候開始，才是起點。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"검은 이터니움… 그러니까, 목표로 하던 <color=#ffd34c>먹의 편린</color>을 대부분 모으면서 당신은 이제 대부분의 기억이 돌아왔을 겁니다.","JPN":"黒いエタニウム……つまり目標にしていた<color=#ffd34c>墨の片鱗</color>をおおかた集めたことで、あなたはほぼすべての記憶を取り戻したはずです。","ENG":"Dark Eternium… So after reaching your goal of gathering most of the <color=#ffd34c>Ink Fragments</color>, I assume most of your memories have returned.","TWN":"黑色永恆之金…也就是說，你收集完大部分的<color=#ffd34c>墨片</color>後，你的大部分記憶應該都回來了吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"어떻습니까? 잃어버린 시간을 돌려받은 소감은?","JPN":"どうですか？　失っていた時間を取り戻した感想は。","ENG":"How does it feel? Getting back your lost time?","TWN":"感覺如何？找回失去的時間的感想？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"글쎄? 별로 아무렇지 않은데?","JPN":"さあ？　別になんともなかったよ。","ENG":"I dunno. It doesn't feel that special.","TWN":"說不好？沒什麼特別的感覺。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어차피 그 기억은 실제로 내가 겪은 일도 아니고, <color=#ffd34c>그랬을 지도 몰랐을</color> 세계선의 일이라며?","JPN":"どうせその記憶は実際私が経験したことでもないし、<color=#ffd34c>そうだったかもしれない</color>世界のことなんでしょう？","ENG":"Those memories weren't even real. They were from a timeline that <color=#ffd34c>might've been</color>, not what I actually experienced.","TWN":"反正那段記憶又不是我親身經歷過的事，而是<color=#ffd34c>可能發生過</color>的平行世界的事不是嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그렇죠.","JPN":"そうですね。","ENG":"True.","TWN":"沒錯。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그자는 당신에게 있어 남이나 다름 없는 인연. 심지어 이 세상에 존재한 적도 없는 만약의 존재.","JPN":"彼はあなたにとっては他人のような因縁。ましてやこの世界には存在したこともない、「もしも」の存在。","ENG":"To you, he's little more than a stranger. Someone who never even truly existed in this world.","TWN":"那個人對你來說，是個陌生人。甚至是在這個世界上從未存在過的如果的存在。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"하지만 그럼에도, 인연의 가능성을 품고 있는 당신이기에 그자의 <color=#ffd34c>편린</color>을 찾을 수 있었던 것이죠.","JPN":"しかしながら、因縁の可能性を秘めているあなただからこそ彼の<color=#ffd34c>片鱗</color>を見つけることができたのです。","ENG":"But because you carry the possibilities of that bond, you were able to find his <color=#ffd34c>fragments</color>.","TWN":"但儘管如此，正因為你擁有緣分的可能性，你才能找到那個人的<color=#ffd34c>碎片</color>。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…가능성이니 다른 세상이니, 그런 건 잘 모르겠어. 별로 와 닿지도 않는 얘기고.","JPN":"……可能性とか別の世界とか、そういうのはよく分からない。正直ピンと来ないし。","ENG":"…All this talk of different worlds and possibilities. I don't really get it. It doesn't feel real to me anyway.","TWN":"…什麼可能性啦，別的世界啦，我都不太懂。感覺也沒什麼真實感。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그냥 관리국 아저씨가 돈을 많이 주니까 열심히 일한 것 뿐인걸.","JPN":"管理局のおじさんがお金をたくさんくれるっていうから、頑張って仕事しただけだよ。","ENG":"I just worked hard because the Administration paid me well. That's it.","TWN":"我只是因為管理局的大叔給了很多錢，所以努力工作而已。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"신용에 감사를. 저 또한 베스카 양의 공사 구분이 명확한 점은 마음에 듭니다.","JPN":"その信用に感謝します。私もまた、ベスカーさんが公私の区別ができる人間であり良かったと思います。","ENG":"Thank you. You're clearly someone who knows how to keep work and personal life separate, Miss Vesca.","TWN":"感謝你的信任。我也很欣賞你公私分明的這一點。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그래서- 마지막 편린은 어디 있는지 찾아냈어?","JPN":"で、最後の片鱗はどこにあるのか分かった？","ENG":"So, any idea where the last fragment is?","TWN":"所以—你找到最後一片碎片在哪了嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"단서는 확보해뒀습니다만…","JPN":"手がかりは確保しましたが……","ENG":"We've found a lead, but…","TWN":"我已經掌握了線索…"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그 전에 먼저 다녀올 곳이 있습니다. 당신이 만나봐야 할 사람도 있고요.","JPN":"その前に訪ねるところがあります。あなたにも、会ってほしい人がいるので。","ENG":"There's somewhere we need to visit first. And someone you should meet.","TWN":"但在那之前，有個地方必須先去一趟。也有個人你必須見見。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"만날 사람?","JPN":"会ってほしい人？","ENG":"Meet someone?","TWN":"要見的人？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오랜만이야, 어르신.","JPN":"久しぶりだね、おばあさん。","ENG":"Long time no see, granny.","TWN":"好久不見，阿姨。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"넌 여전하군. 예전이랑 달라진 게 없어 보여.","JPN":"お前は相変わらずだな。昔とまったく同じだ。","ENG":"You haven't changed a bit. Still looking the same as ever.","TWN":"你還是一樣。看起來和以前沒有任何變化。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"10년만인가? 그동안 어떻게 지냈어?","JPN":"10年ぶりかな？　今まで何して過ごしてた？","ENG":"What's it been? Ten years? How've you been?","TWN":"十年了嗎？這些年過得怎麼樣？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"형식적인 얘기는 나중에 하지. 다른 중요한 볼일이 있을 테니까.","JPN":"形式的な話は後にしよう。他に重要な用事があるだろうから。","ENG":"Save the small talk. We've got more important matters to discuss.","TWN":"客套話之後再說。你應該還有其他重要的事。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"성격은 여전하구나.","JPN":"その性格は変わってないんだね。","ENG":"Glad to see your personality hasn't changed either.","TWN":"個性還是一樣呢。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"주시윤이라고 했던가? 아까 장례 끝나고 흰머리 여자애랑 같이 떠난 꼬맹이 말이야.","JPN":"アキヤマ・シリュウって言ったっけ。さっきお葬式が終わって白い髪の毛の女の子と一緒に帰った子。","ENG":"Joo Shiyoon, was it? The kid who left after the funeral with that white-haired girl.","TWN":"你說周時雲？剛才葬禮結束，和那個白髮女生一起離開的小鬼。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"연화 씨의 아이… 맞지?","JPN":"レンカさんの子ども……だよね？","ENG":"He's Yeonhwa's son… right?","TWN":"是蓮華姊姊的孩子…對吧？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"얼마 전 혼자 남겨졌다.","JPN":"今後は天涯孤独の身として生きていくだろう。","ENG":"He was left alone not long ago.","TWN":"不久前，他一個人留了下來。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…그렇게 됐구나.","JPN":"……そうなんだ。","ENG":"…So it happened after all.","TWN":"…變成這樣了啊。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"결국 이야기에 반전은 없었던 거네. 우려했던 운명이란 건, 끝내 변치 않았으니까.","JPN":"結局、物語にどんでん返しなんかなかったんだね。恐れていた運命は、最後まで変わらなかったんだから。","ENG":"No plot twist in the story, then. Fate played out unchanged just as we feared.","TWN":"結果故事沒有反轉。擔心的命運，終究沒有改變。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그 끝이 비극이라 해도, 지난 시간이 무의미했다는 뜻은 아니지.","JPN":"最後が悲劇だったとしても、それが今までの時間が無意味だったという意味ではない。","ENG":"Even if it ended in tragedy, that doesn't mean the time they shared was worthless.","TWN":"就算那個結局是個悲劇，也不代表過去的時光是沒有意義的。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어쩌면, 저 꼬마에겐 이 비극이 운명의 전환점이 될지도 모르고 말이야.","JPN":"もしかしたらこの悲劇が、あのガキにとって運命の転機になるかもしれないしな。","ENG":"Maybe it'll be the trigger that helps that kid grow stronger.","TWN":"或許，這個悲劇，會成為那個小鬼命運的扳機。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 모든 비극이 성장의 계기가 된다라… 왠지 매정하게 느껴지는 표현이네.","JPN":"このすべての悲劇が成長のきっかけになる……なんか薄情に聞こえる表現だね。","ENG":"Calling all this tragedy a stepping stone for growth… That's a pretty cold way to put it.","TWN":"這所有悲劇都成為成長的契機…這句話聽起來有點無情。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하긴, 장례식에 와서 남의 운명이나 들먹이는 나도 별반 다르지 않나?","JPN":"まあ、人のお葬式に来て運命だの何だの言ってる私もそう変わらないか。","ENG":"But I guess I'm no better, showing up at a funeral and analyzing it like this.","TWN":"也是，連我這個來參加別人葬禮，還在分析這些的人，也沒什麼不同。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래서, 네가 찾는 마지막 편린은 어디에 있지?","JPN":"それで、お前が探している最後の片鱗はどこにある？","ENG":"So, where's the last fragment you're looking for?","TWN":"所以，你找到你找的最後一片碎片在哪了嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>먹의 편린</color>은 내 사부란 사람의 혼백이 품고 있던 백 가지의 미련…","JPN":"<color=#ffd34c>墨の片鱗</color>は私の師匠って人の魂魄が抱いていた100の未練……","ENG":"The <color=#ffd34c>Ink Fragments</color> are the hundred lingering regrets that clung to the soul of the one I once called Master.","TWN":"<color=#ffd34c>墨片</color>是我師父的魂魄所懷抱的一百個遺憾…"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 중 마지막 한 조각이 관측된 곳은…","JPN":"最後の片鱗が観測された場所は……","ENG":"And the last piece was traced to…","TWN":"其中最後一片被觀測到的地方是…"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…저 아이의 심장이야.","JPN":"……あの子の心臓だよ。","ENG":"…That kid's heart.","TWN":"…那個孩子的，心臟。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그 말은…","JPN":"それは……","ENG":"You're saying…","TWN":"你的意思是…"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"편린을 얻으려면 저 꼬마에게 손을 대야한다는 거군.","JPN":"片鱗を手に入れるためには、ガキに手を出さねばならないということか。","ENG":"To get that fragment, you'll have to harm that child?","TWN":"要得到碎片，就要對那個小鬼動手嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"무서운 소릴 하네. 뭐, 그것도 틀린 방법은 아니지만.","JPN":"怖いことをいうな～まあ、それも方法ではあるけどね。","ENG":"Now that's a scary way to put it. Not wrong, but still.","TWN":"說得這麼可怕。不過，那確實是不錯的方法"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"할 수만 있다면… 잠시 기다려보는 것도 괜찮지 않아?","JPN":"できれば……もうちょっと待ってみるのもありなんじゃない？","ENG":"If we can avoid it… maybe it's better to wait a little.","TWN":"如果可以的話…等一下也沒關係吧？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"편린이 꼭 사람의 몸 밖에 있어야만 제 역할을 할 수 있단 얘긴 없었으니까.","JPN":"片鱗が体の外にないと役割を果たせないって話、なかったしね。","ENG":"No one said a fragment has to exist outside the person, right?","TWN":"沒有規定碎片一定要在人的身體外面。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"여전히 대책도 없으면서 낙관적이기만 하군.","JPN":"相変わらず、これといった対策もないくせに楽観的だな。","ENG":"Still reckless and optimistic, as ever.","TWN":"你還是一樣，沒有對策卻總是那麼樂觀。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"훗날 저 꼬마가 장성 해서, 우리와 순순히 협력할지도 모른단 말을 하고 싶은 거냐?","JPN":"将来あのガキが成長して、素直に私たちに協力してくれるかもしれないと期待しているのか？","ENG":"You're hoping the kid grows up and chooses to help us willingly?","TWN":"你是想說，日後那個小鬼長大，會乖乖和我們合作嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그 부모처럼 용혈에 잠식되어 똑같은 최후를 맞게 될 거라는… 그런 당연한 생각조차 안 거친 건 아니겠지?","JPN":"親のように龍血に支配され、同じ最期を迎えるという……当たり前のことを忘れたわけじゃないだろうな。","ENG":"Have you considered the obvious? That like his parents, he might be consumed by the Dragon Blood… and meet the same end?","TWN":"你不會連他會像他父母一樣被龍血侵蝕，最終迎來同樣結局的這種理所當然的想法都沒考慮過吧？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"설령 그렇게 된다고 해도…","JPN":"もしそうなるとしても……","ENG":"Even if that's how it ends…","TWN":"就算那樣…"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"시간을 주는 것에 의미가 있다고 생각해.","JPN":"時間をあげることに意味があるんだと思う。","ENG":"I still think there's value in giving him time.","TWN":"我認為給予時間是有意義的。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우리가 앞서 <color=#ffd34c>그 사람들</color>에게 받은 그것처럼…","JPN":"私たちが<color=#ffd34c>あの人たち</color>にもらったように……","ENG":"Just like the time <color=#ffd34c>they</color> gave us…","TWN":"就像我們從<color=#ffd34c>那些人</color>那裡得到的一樣…"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 끝에 어떤 결말이 기다린다 하더라도, 무의미한 시간 같은 건 없는 거잖아?","JPN":"その先にどんな結末が待っていたとしても、無意味な時間なんてないんでしょ？","ENG":"No matter what the ending looks like, there's no such thing as meaningless time, right?","TWN":"無論最終等待著什麼樣的結局，沒有時間是沒有意義的，對吧？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시간을 하루라도 아껴야 하는 때에, 중요한 계획의 마지막 파편을 몇 년이 될지도 모르는 세월을 두고 지켜보자니.","JPN":"時間を1日でも短縮したい時に……大事な計画に必要な最後の破片を、無期限で様子見とは。","ENG":"In a time when every day counts, we're leaving the final piece of a vital plan up to years of uncertainty.","TWN":"在連一天時間都必須珍惜的時候，重要的計畫最後一片碎片，卻要等待可能長達數年的歲月。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이거, 지수 씨가 정말 터무니 없는 약속을 해버린 것 같군요. 제가 그 자리에 있었다면 그런 판단은 내리지 않았을 겁니다.","JPN":"シノさん、とんでもない約束をしましたね。あの場にいたのが僕なら、そんな判断はしなかったはずです。","ENG":"Quite the outrageous promise you made, Jisoo. If I'd been there, I wouldn't have made that call.","TWN":"李智秀，你真的做出了一個荒謬的承諾。如果我在場，我不會做出那樣的判斷。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…면목 없습니다, 대장.","JPN":"……申し訳ありません、隊長。","ENG":"…I accept full responsibility, Commander.","TWN":"…很抱歉，隊長。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇게 됐으니, 철저히 감시해주세요.","JPN":"こうなったからには、徹底的に監視してください。","ENG":"In that case, make sure he's under constant surveillance.","TWN":"既然如此，請你務必嚴密監視。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"개입하지 않는 겁니까?","JPN":"介入しないんですか？","ENG":"You're not going to intervene?","TWN":"你不打算介入嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지수 씨 말대로 한 번 그 꼬마를 지켜보도록 하죠.","JPN":"シノさんの言う通り、一旦は見守ってみましょう。","ENG":"Let's try it your way.","TWN":"就照智秀說的，觀察那個小鬼一次吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다만 저희가 기다릴 수 있는 건, 클리포트 게임이 시작되기 전까지가 한계입니다. 그 아이는 그때까지 자신의 가능성을 증명해야만 할 거에요.","JPN":"ただ、僕たちが待っていられるのは……せいぜいクリフォトゲームが始まる前までになります。その間に、あの子には自分の可能性を証明してもらわなければなりません。","ENG":"But our patience will only last until the Qliphoth Game begins. The child will have to prove their potential by then.","TWN":"但是我們能等待的極限，是在逆卡巴拉遊戲開始之前。那個孩子必須在那之前證明自己的可能性。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};